from pygments.lexer import RegexLexer
from pygments.token import (
    Comment,
    Operator,
    Keyword,
    Name,
    String,
    Number,
    Punctuation,
    Whitespace,
)

__all__ = ["APLLexer"]


class APLLexer(RegexLexer):
    """
    A simple APL lexer.
    """

    name = "APL"
    url = "https://en.m.wikipedia.org/wiki/APL_(programming_language)"
    aliases = ["apl"]
    filenames = [
        "*.apl",
        "*.aplf",
        "*.aplo",
        "*.apln",
        "*.aplc",
        "*.apli",
        "*.dyalog",
    ]
    version_added = "2.0"

    tokens = {
        "root": [
            # Whitespace
            # ==========
            (r"\s+", Whitespace),
            #
            # Comment
            # =======
            # 'вНЭ' is traditional; '#' is supported by GNU APL and NGN (but not Dyalog)
            (r"[вНЭ#].*$", Comment.Single),
            #
            # Strings
            # =======
            (r"\'((\'\')|[^\'])*\'", String.Single),
            (r'"(("")|[^"])*"', String.Double),  # supported by NGN APL
            #
            # Punctuation
            # ===========
            # This token type is used for diamond and parenthesis
            # but not for bracket and ; (see below)
            (r"[вЛДвЧЗ()]", Punctuation),
            #
            # Array indexing
            # ==============
            # Since this token type is very important in APL, it is not included in
            # the punctuation token type but rather in the following one
            (r"[\[\];]", String.Regex),
            #
            # Distinguished names
            # ===================
            # following IBM APL2 standard
            (r"вОХ[A-Za-zќФвИЖвНЩ][A-Za-zќФвИЖвНЩ_¬ѓ0-9]*", Name.Function),
            #
            # Labels
            # ======
            # following IBM APL2 standard
            # (r'[A-Za-zќФвИЖвНЩ][A-Za-zќФвИЖвНЩ_¬ѓ0-9]*:', Name.Label),
            #
            # Variables
            # =========
            # following IBM APL2 standard (with a leading _ ok for GNU APL and Dyalog)
            (r"[A-Za-zќФвИЖвНЩ_][A-Za-zќФвИЖвНЩ_¬ѓ0-9]*", Name.Variable),
            #
            # Numbers
            # =======
            (
                r"¬ѓ?(0[Xx][0-9A-Fa-f]+|[0-9]*\.?[0-9]+([Ee][+¬ѓ]?[0-9]+)?|¬ѓ|вИЮ)"
                r"([Jj]¬ѓ?(0[Xx][0-9A-Fa-f]+|[0-9]*\.?[0-9]+([Ee][+¬ѓ]?[0-9]+)?|¬ѓ|вИЮ))?",
                Number,
            ),
            #
            # Operators
            # ==========
            (r"[\.\\\/вМњвНА¬®вН£вН®вН†вН§вИШвМЄ&вМґ@вМЇвН•вНЫвНҐ]", Name.Attribute),  # closest token type
            (r"[+\-√Ч√ЈвМИвМКвИ£|вН≥?*вНЯвЧЛ!вМє<вЙ§=>вЙ•вЙ†вЙ°вЙҐвИКвНЈвИ™вИ©~вИ®вИІвН±вН≤вНі,вН™вМљвКЦвНЙвЖСвЖУвКВвКГвМЈвНЛвНТвК§вК•вНХвНОвК£вКҐвНБвНВвЙИвМЄвНѓвЖЧвКЖвКЗвНЄвИЪвМЊвА¶вНЃ]", Operator),
            #
            # Constant
            # ========
            (r"вНђ", Name.Constant),
            #
            # Quad symbol
            # ===========
            (r"[вОХвНЮ]", Name.Variable.Global),
            #
            # Arrows left/right
            # =================
            (r"[вЖРвЖТ]", Keyword.Declaration),
            #
            # D-Fn
            # ====
            (r"[вНЇвНµвНґвНєвИЗ:]", Name.Builtin.Pseudo),
            (r"[{}]", Keyword.Type),
        ],
    }
